import sqlite3
from contextlib import contextmanager

DB_PATH = "data.db"


@contextmanager
def get_conn():
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    try:
        yield conn
        conn.commit()
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()


def fetch_all(query: str, params=()) -> list:
    with get_conn() as conn:
        return conn.execute(query, params).fetchall()

